/**
 * Errors exposed across the FFI boundary.
 */
public enum CoreError: Swift.Error, Equatable, Hashable, Foundation.LocalizedError {

    
    
    case ModelNotFound(String
    )
    case ModelLoadFailed(String
    )
    case TranscriptionFailed(String
    )
    case LlmError(String
    )
    case ConfigError(String
    )
    case AudioError(String
    )
    case IoError(String
    )

    

    

    
    public var errorDescription: String? {
        String(reflecting: self)
    }
    
}

#if compiler(>=6)
extension CoreError: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeCoreError: FfiConverterRustBuffer {
    typealias SwiftType = CoreError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> CoreError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .ModelNotFound(
            try FfiConverterString.read(from: &buf)
            )
        case 2: return .ModelLoadFailed(
            try FfiConverterString.read(from: &buf)
            )
        case 3: return .TranscriptionFailed(
            try FfiConverterString.read(from: &buf)
            )
        case 4: return .LlmError(
            try FfiConverterString.read(from: &buf)
            )
        case 5: return .ConfigError(
            try FfiConverterString.read(from: &buf)
            )
        case 6: return .AudioError(
            try FfiConverterString.read(from: &buf)
            )
        case 7: return .IoError(
            try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: CoreError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .ModelNotFound(v1):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(v1, into: &buf)
            
        
        case let .ModelLoadFailed(v1):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(v1, into: &buf)
            
        
        case let .TranscriptionFailed(v1):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(v1, into: &buf)
            
        
        case let .LlmError(v1):
            writeInt(&buf, Int32(4))
            FfiConverterString.write(v1, into: &buf)
            
        
        case let .ConfigError(v1):
            writeInt(&buf, Int32(5))
            FfiConverterString.write(v1, into: &buf)
            
        
        case let .AudioError(v1):
            writeInt(&buf, Int32(6))
            FfiConverterString.write(v1, into: &buf)
            
        
        case let .IoError(v1):
            writeInt(&buf, Int32(7))
            FfiConverterString.write(v1, into: &buf)
            
        }
    }
}


